+    fn events_annotate_tool_applies_mcp_mutation_policy_gate() {
+        let (_dir, db_path) = temp_db_path();
+        let event_id = seed_event(db_path.as_ref().as_path());
+        let tool = WaEventsAnnotateTool::new(
